pratica_guiada.python:
pacotes_despachados = []

# Fase 1: Coletar até ao fim do turno
while True:
    codigo = input("Código do pacote (ou 'encerrar'): ")
    if codigo == "encerrar":
        break
    # O input lê como texto, mas para procurar e comparar preferimos números
    pacotes_despachados.append(int(codigo))

# Fase 2 e 3: O balanço de segurança
pacote_urgente_enviado = False

for pacote in pacotes_despachados:
    if pacote == 999:
        pacote_urgente_enviado = True

# Relatório final
if pacote_urgente_enviado:
    print("Sucesso! O pacote de urgência médica seguiu no camião.")
else:
    print("Alerta: O pacote prioritário 999 ficou esquecido no armazém.")
